/**
 * Builds *.templates.js from HTML/SVG source files in templates/.
 *
 * For each subdirectory in templates/:
 * 1. Reads SVG partials from svg/
 * 2. Reads HTML templates from the directory root
 * 3. Resolves {{> path}} partial includes by inlining file content
 * 4. Generates <name>.templates.js with named camelCase exports
 *
 * Generated files are intermediate artifacts (gitignored); build-js.js
 * inlines them into the root JS build outputs.
 */

import { readFileSync, readdirSync, existsSync, writeFileSync } from 'fs';
import { resolve, dirname, basename } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, '..');
const TEMPLATES_ROOT = resolve(ROOT, 'src', 'templates');

for (const dir of readdirSync(TEMPLATES_ROOT)) {
  const templateDir = resolve(TEMPLATES_ROOT, dir);
  const svgDir = resolve(templateDir, 'svg');
  const output = resolve(ROOT, 'src', `${dir}.templates.js`);

  // Load SVG partials
  const svgs = {};
  if (existsSync(svgDir)) {
    for (const file of readdirSync(svgDir)) {
      if (file.endsWith('.svg')) {
        svgs[`svg/${file}`] = readFileSync(resolve(svgDir, file), 'utf8').trim();
      }
    }
  }

  // Load HTML templates
  const templates = {};
  for (const file of readdirSync(templateDir)) {
    if (file.endsWith('.html')) {
      const name = basename(file, '.html').replace(/-([a-z])/g, (_, c) => c.toUpperCase());
      let html = readFileSync(resolve(templateDir, file), 'utf8').trim();

      // Resolve partial includes: {{> svg/person-icon.svg}}
      html = html.replace(/\{\{>\s*(.+?)\s*\}\}/g, (_, path) => {
        if (!svgs[path]) {
          throw new Error(`Unknown partial: ${path} in ${dir}/${file}`);
        }
        return svgs[path];
      });

      templates[name] = html;
    }
  }

  // Generate output
  const lines = ['// Auto-generated by scripts/build-templates.js — do not edit manually', ''];

  for (const [name, html] of Object.entries(templates).sort(([a], [b]) => a.localeCompare(b))) {
    lines.push(`export const ${name} = ${JSON.stringify(html)};`);
    lines.push('');
  }

  writeFileSync(output, lines.join('\n'));
}
